var installCmd = "puzzle add piece accordion";
var usageImport = `import Accordion from '@/components/ui/Accordion.pzl';`;
var usageMarkup = `<Accordion items={ faq } value={ open } @change={ setOpen }/>`;
var codeHero = `const faq = [
  { id: 'q1', title: 'What is puzzle-pieces?', content: 'A registry of copy-in components.' },
  { id: 'q2', title: 'How do I add a piece?', content: 'Copy its .pzl file into your app.' },
  { id: 'q3', title: 'Can I customize a piece?', content: 'Yes \u2014 once copied the file is yours.' },
];

// single (default) \u2014 one open at a time; '' means all closed
<Accordion items={ faq } value={ open } @change={ setOpen }/>

// parent
events = { setOpen: (id) => this.setData('open', id) };`;
var codeMultiple = `const specs = [
  { id: 's1', title: 'Dimensions', content: '\u2026' },
  { id: 's2', title: 'Accessibility', content: '\u2026' },
  { id: 's3', title: 'Theming', content: '\u2026' },
];

// multiple \u2014 value is an array of open ids
<Accordion type="multiple" items={ specs } value={ open } @change={ setOpen }/>

// parent
events = { setOpen: (ids) => this.setData('open', ids) };`;
var codeCompose = `// Rich per-item markup \u2192 compose Collapsible, own exclusivity in the parent
{#for item in items}
  <Collapsible label={ item.title }
               open={ openId === item.id }
               @change={ () => setOpenId(openId === item.id ? '' : item.id) }>
    <RichMarkup .../>
  </Collapsible>
{/for}`;
