var codeHero26 = `const columns = [
  { key: 'invoice', label: 'Invoice', sortable: true },
  { key: 'client', label: 'Client', sortable: true },
  { key: 'status', label: 'Status' },
  { key: 'amount', label: 'Amount', align: 'right', sortable: true },
];

// rowKey is the stable id used for selection; pageSize turns on pagination.
<DataTable columns={ columns } rows={ rows } rowKey="invoice"
           selectable pageSize={ 5 } />`;
var codeSorting = `// Sort is optional-controlled: the parent owns the descriptor and
// @sortChange hands back the next state on each header click. The table
// applies it to the full row set (numeric compare when both cells read as
// finite numbers, else localeCompare). Omit sort to let the table own it.
<DataTable columns={ columns } rows={ rows } rowKey="invoice"
           sort={ sort } @sortChange={ setSort } />

events = {
  setSort: (next) => this.setData({ sort: next }),   // { key, dir } | null
};`;
var codeSelection = `// selected is an array of rowKey values; @select fires the next array.
// Keys are row ids, so a selection survives sorting and paging. The header
// checkbox selects/clears the current page and goes indeterminate when
// the page is partially selected.
<DataTable columns={ columns } rows={ rows } rowKey="invoice"
           selectable selected={ selected } @select={ setSelected } />
<p>{ selected.length } selected</p>

events = {
  setSelected: (keys) => this.setData({ selected: keys }),
};`;
var codePagination = `// pageSize enables pagination (rows are sorted, THEN paged); the footer
// shows "x\u2013y of z" and the Pagination strip. page is optional-controlled \u2014
// omit it to let the table track the page itself.
<DataTable columns={ columns } rows={ rows } rowKey="invoice"
           pageSize={ 4 } page={ page } @pageChange={ setPage } />

events = {
  setPage: (n) => this.setData({ page: n }),
};`;
